        expect(u.externalKey).toBe('320001TUR-0228');
        expect(u.name).toBe('FAB-0228-L37-SUP-PKG-EAST');
        expect(u.newDurationMinutes).toBe(3 * 480);
        expect(u.newPercentComplete).toBe(80); // Issued for Fabrication → 80%
        expect(u.notesAppend).toContain('Test note');
